objects.paper_statement:
For a subset of the ambient complex affine space, write \(\operatorname{ZariskiClosure}\) for its Zariski closure. Using the parameter spaces and maps of Definitions~\ref{obj:def:forward-cumulant-map} and~\ref{obj:def:reverse-cumulant-map}, the forward and reverse image varieties are
\[
C^{\mathrm{right}}_{m,L}
=
\operatorname{ZariskiClosure}
\bigl(\Phi^{\mathrm{right}}_{m,L}(\Theta^{\mathrm{right}}_{m,L})\bigr),
\qquad
C^{\mathrm{left}}_{m,L}
=
\operatorname{ZariskiClosure}
\bigl(\Phi^{\mathrm{left}}_{m,L}(\Theta^{\mathrm{left}}_{m,L})\bigr),
\]
as subvarieties of \(\mathbb C^{q_L}\).

bcc866ff938b9f92.statement:
/-- Observable truncated-cumulant coordinate vector `t ∈ R^{q_L}`, indexed by
`(r, a)` with `2 ≤ r ≤ L`, `0 ≤ a ≤ r`.
@realizes T_L(P),t(coordinate family (r,a) ↦ t_{r,a})
@realizes kappa_{r,a}(P)(coordinate (r,a)) -/
abbrev CumVec (R : Type*) : Type _ := ℕ → ℕ → R

81de0bfd0fdc9abf.statement:
-- @env: S2
/-- Structural parameter space `Θ^b_{m,L} = R^{m+1} × R^{n(L-1)}`.  The three
components are the direct slope, the `m` latent-loading slopes, and the
source-cumulant weight family `(j, r) ↦ c_{jr}`.
@realizes Theta^right_{m,L},Theta^left_{m,L},theta,eta(coordinates (γ/δ, ρ/σ, c/d))
@realizes gamma(component `.1`)  @realizes rho_i(component `.2.1`)
@realizes delta(component `.1`)  @realizes sigma_i(component `.2.1`)
@realizes c_{jr},d_{jr}(component `.2.2 j r`) -/
abbrev ParamSpace (R : Type*) (m : ℕ) : Type _ :=
  R × (Fin m → R) × (Fin (m + 2) → ℕ → R)

ad65a3f7d5d2b552.statement:
def genericParameterLocus {R : Type*} [CommRing R] (m L : ℕ) :
    Set (ParamSpace R m) :=
  bandSupportedParams m L ∩ { θ |
      θ.1 * (∏ i : Fin m, (θ.1 - θ.2.1 i))
        * (∏ i : Fin m, ∏ i' : Fin m, if i < i' then θ.2.1 i - θ.2.1 i' else 1)
        * (∏ j : Fin (m + 2), ∏ r ∈ Finset.Icc 2 L, θ.2.2 j r) ≠ 0 }

e6ceed783e396f7a.statement:
def fiberCorrespondence {R : Type*} [Zero R] (L : ℕ)
    (Φ : ParamSpace R m → CumVec R) (t : CumVec R) : Set (ParamSpace R m) :=
  bandSupportedParams m L ∩
    { θ | ∀ r a : ℕ, 2 ≤ r → r ≤ L → a ≤ r → Φ θ r a = t r a }

2675a14f04fd9dfd.statement:
/-- Reverse atlas section over `t`: the `t`-fiber of `Γ_left` (local description of
`R^left_{m,K}(t) ∩ F^left`). -/
def realAtlasReverseSection (m : ℕ) (t : CumVec ℝ) : Set (ParamSpace ℝ m) :=
  { lam | (t, lam) ∈ realAtlasHandleReverse m }

7d5801119e197ba3.statement:
/-- Reverse atlas nonemptiness label `ε^left(t)`. -/
def realAtlasReverseLabel (m : ℕ) (t : CumVec ℝ) : Prop :=
  (realAtlasReverseSection m t).Nonempty

49d11fc7e88031e0.statement:
/-- The real exceptional locus in the finite observable coordinate space used by
the incidence handles: membership in `bar E_m(ℝ)` together with zero coordinates
off the retained band `2 ≤ r ≤ 2m+2`, `0 ≤ a ≤ r`. -/
def bandLimitedRealExceptionalLocus (m : ℕ) : Set (CumVec ℝ) :=
  { t | IsAtlasBandLimited m t ∧
      complexifyCumVec t ∈ genericCompatibilityClosure m }

e69b2397d7dda2a0.statement:
/-- Complexification of a real structural parameter, coordinatewise. -/
def complexifyParam {m : ℕ} (p : ParamSpace ℝ m) : ParamSpace ℂ m :=
  ((p.1 : ℂ), (fun i => (p.2.1 i : ℂ)), (fun j r => (p.2.2 j r : ℂ)))
